        [hashtable]$ver = @{ Major = 1; Minor = 2; Patch = 3 }
        [hashtable]$result = Update-SemanticVersion -Version $ver -BumpType 'minor'
        $result.Major | Should -Be 1
        $result.Minor | Should -Be 3
        $result.Patch | Should -Be 0
    }

