        [hashtable]$ver = @{ Major = 1; Minor = 2; Patch = 3 }
        [hashtable]$result = Update-SemanticVersion -Version $ver -BumpType 'major'
        $result.Major | Should -Be 2
        $result.Minor | Should -Be 0
        $result.Patch | Should -Be 0
    }

